-- Veridian Bank Audit Log Schema
-- SOX/PCI-DSS compliant append-only audit table

CREATE TABLE IF NOT EXISTS audit_log (
    entry_id        UUID PRIMARY KEY,
    transaction_id  VARCHAR(64) NOT NULL,
    timestamp       TIMESTAMP WITH TIME ZONE NOT NULL,
    operation_type  VARCHAR(32) NOT NULL,
    amount          NUMERIC(18, 2) NOT NULL,
    account_id      VARCHAR(32) NOT NULL,
    user_id         VARCHAR(64) NOT NULL,
    metadata        JSONB DEFAULT '{}',
    previous_hash   VARCHAR(128),
    entry_hash      VARCHAR(128) NOT NULL,
    sequence_number BIGSERIAL NOT NULL,
    created_at      TIMESTAMP WITH TIME ZONE DEFAULT NOW()
);

-- Enforce append-only via trigger
CREATE OR REPLACE FUNCTION prevent_audit_modification()
RETURNS TRIGGER AS $$
BEGIN
    RAISE EXCEPTION 'Audit log entries cannot be modified or deleted';
    RETURN NULL;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER audit_log_immutable
    BEFORE UPDATE OR DELETE ON audit_log
    FOR EACH ROW
    EXECUTE FUNCTION prevent_audit_modification();

-- Index for reconciliation queries
CREATE INDEX idx_audit_log_timestamp ON audit_log (timestamp);
CREATE INDEX idx_audit_log_transaction ON audit_log (transaction_id);
CREATE INDEX idx_audit_log_sequence ON audit_log (sequence_number);

